<template><div class="page"><TopBar :title="title"/><section v-if="kind!=='settings'" class="filters"><input v-model="keyword" placeholder="搜索订单号、买家或商品" @keyup.enter="load"><select v-if="kind!=='finance'" v-model="status" @change="load"><option value="">全部状态</option><option v-for="x in statuses" :value="x[1]">{{x[0]}}</option></select><button @click="load">查询</button></section><p v-if="loading" class="empty">加载中...</p><section v-else-if="error" class="card error-state"><p>{{error}}</p><button @click="load">重试</button></section><template v-else-if="detail"><section class="card detail"><h2>{{detail.title||detail.orderNo}}</h2><p v-for="(v,k) in detail" v-show="simple(v)"><b>{{labels[k]||k}}</b><span>{{v}}</span></p></section></template><template v-else-if="kind==='settings'"><section class="card detail"><h2>{{data.siteName}}</h2><p><b>Dujiao API</b><span>{{data.integrations?.dujiao?'已连接':'未连接'}}</span></p><p><b>LHC</b><span>{{data.integrations?.lhc?'已连接':'未连接'}}</span></p><p><b>支付配置</b><span>{{data.paymentConfigured?'已配置':'未确认'}}</span></p><p><b>发货配置</b><span>{{data.fulfillmentConfigured?'已配置':'未确认'}}</span></p></section><button class="logout" @click="logout">退出登录</button></template><template v-else><section v-if="kind==='finance'" class="core summary"><article><span>今日收入</span><b>¥{{summary.todayIncome}}</b></article><article><span>总收入</span><b>¥{{summary.totalIncome}}</b></article><article><span>退款</span><b>¥{{summary.refundAmount}}</b></article></section><p v-if="!items.length" class="empty">{{empty}}</p><section class="records"><article v-for="x in items" @click="open(x.id)"><div><strong>{{x.title||x.orderNo||x.typeText}}</strong><small>{{x.productTitle||x.categoryName||x.channel}}</small></div><div><b>¥{{x.price||x.payAmount||x.amount}}</b><span>{{x.statusText}}</span><small>{{x.createdAt}}</small></div></article></section></template></div></template>
<script setup lang="ts">import{onMounted,ref}from'vue';import TopBar from'../components/TopBar.vue';import{navigate,route}from'../router';import{logout}from'../auth';const props=defineProps<{kind:string,title:string}>(),loading=ref(false),error=ref(''),items=ref<any[]>([]),data=ref<any>({}),detail=ref<any>(),summary=ref<any>({}),keyword=ref(''),status=ref('');const statuses=[['待付款','pending_payment'],['待发货','pending_delivery'],['已发货','delivered'],['已完成','completed'],['已关闭','closed'],['上架','on_sale'],['下架','off_sale']],empty=props.kind==='orders'?'暂无订单':props.kind==='products'?'暂无商品':'暂无财务记录',labels:any={orderNo:'订单号',buyerName:'买家',buyerContact:'联系方式',productTitle:'商品',payAmount:'支付金额',statusText:'状态',createdAt:'创建时间',paidAt:'支付时间',title:'商品名称',price:'价格',stock:'库存',description:'描述',categoryName:'分类',updatedAt:'更新时间'};const simple=(v:any)=>['string','number','boolean'].includes(typeof v);async function load(){loading.value=true;error.value='';try{const id=route.value.path.match(new RegExp(`^/${props.kind}/([^/]+)$`))?.[1],q=new URLSearchParams({page:'1',pageSize:'20',keyword:keyword.value,status:status.value}),r=await fetch(`/api/koshop-seller/${props.kind}${id?'/'+id:'?'+q}`),j=await r.json();if(!r.ok||!j.ok)throw Error(j.message);if(id)detail.value=j.data;else if(props.kind==='settings')data.value=j.data;else{items.value=j.items||[];summary.value=j.summary||{}}}catch(e:any){error.value=e.message||'Dujiao Admin 接口暂不可用'}finally{loading.value=false}}function open(id:any){if(['orders','products'].includes(props.kind))navigate(`/${props.kind}/${id}`)}onMounted(load)</script>
